(function() { 'use strict'; const STORAGE_KEY = 'kbt-theme'; const DARK_CLASS = 'dark-theme'; const DEBUG = false; function log(...args) { if (DEBUG) console.log('[Theme]', ...args); } function getStoredTheme() { const stored = localStorage.getItem(STORAGE_KEY); log('getStoredTheme:', stored || 'none (using system preference)'); if (stored) return stored; if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) { return 'dark'; } return 'light'; } function applyTheme(theme) { log('applyTheme called with:', theme); const isDark = theme === 'dark'; document.documentElement.classList.remove('dark-theme', 'light-theme'); document.documentElement.classList.add(isDark ? 'dark-theme' : 'light-theme'); document.documentElement.setAttribute('data-theme', theme); if (document.body) { document.body.classList.remove('dark-theme', 'light-theme'); document.body.classList.add(isDark ? 'dark-theme' : 'light-theme'); document.body.setAttribute('data-theme', theme); } localStorage.setItem(STORAGE_KEY, theme); log('Theme stored in localStorage:', theme); log('HTML classes:', document.documentElement.className); log('HTML data-theme:', document.documentElement.getAttribute('data-theme')); if (DEBUG && document.body) { requestAnimationFrame(() => { const bgColor = getComputedStyle(document.body).backgroundColor; const textColor = getComputedStyle(document.body).color; log('Body background color:', bgColor); log('Body text color:', textColor); }); } const buttons = document.querySelectorAll('.theme-toggle, #themeToggle, [data-theme-toggle]'); buttons.forEach(btn => { btn.textContent = isDark ? '☀️' : '🌙'; log('Updated button icon to:', btn.textContent); }); window.dispatchEvent(new CustomEvent('themechange', { detail: { theme } })); } function toggleTheme() { const currentTheme = document.documentElement.classList.contains(DARK_CLASS) ? 'dark' : 'light'; const newTheme = currentTheme === 'dark' ? 'light' : 'dark'; log('toggleTheme: switching from', currentTheme, 'to', newTheme); applyTheme(newTheme); return newTheme; } function init() { log('init() called, readyState:', document.readyState); const theme = getStoredTheme(); applyTheme(theme); if (document.readyState === 'loading') { document.addEventListener('DOMContentLoaded', setupToggleButtons); } else { setupToggleButtons(); } if (window.matchMedia) { window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', (e) => { if (!localStorage.getItem(STORAGE_KEY)) { applyTheme(e.matches ? 'dark' : 'light'); } }); } } function setupToggleButtons() { log('setupToggleButtons() called'); const selectors = [ '.theme-toggle', '#theme-toggle', '#themeToggle', '[data-theme-toggle]', '.dark-mode-toggle', '#darkModeToggle' ]; let buttonsFound = 0; selectors.forEach(selector => { const buttons = document.querySelectorAll(selector); buttons.forEach(button => { if (button.dataset.themeBound === 'true') { log('Button already bound:', selector); return; } buttonsFound++; log('Binding click handler to:', selector, button); button.addEventListener('click', (e) => { e.preventDefault(); e.stopPropagation(); log('Button clicked!'); button.style.transform = 'scale(0.9)'; setTimeout(() => { button.style.transform = ''; }, 100); toggleTheme(); }); button.dataset.themeBound = 'true'; }); }); log('Total buttons bound:', buttonsFound); if (buttonsFound === 0) { log('WARNING: No theme toggle buttons found!'); } } init(); window.KBTTheme = { toggle: toggleTheme, set: applyTheme, get: () => document.documentElement.classList.contains(DARK_CLASS) ? 'dark' : 'light', debug: () => { log('Current state:'); log('- localStorage:', localStorage.getItem(STORAGE_KEY)); log('- HTML class:', document.documentElement.className); log('- data-theme:', document.documentElement.getAttribute('data-theme')); log('- Body bg:', document.body ? getComputedStyle(document.body).backgroundColor : 'no body'); }, STORAGE_KEY }; log('Theme.js loaded successfully'); })();